import torch

def kl_divergence_torch(p: torch.Tensor, q: torch.Tensor) -> float:
    p = p.to(torch.float64)
    q = q.to(torch.float64)

    if not (torch.all(p >= 0) and torch.allclose(p.sum(), torch.tensor(1.0, dtype=torch.float64), atol=1e-6)):
        raise ValueError("p is not a valid probability distribution")
    if not (torch.all(q >= 0) and torch.allclose(q.sum(), torch.tensor(1.0, dtype=torch.float64), atol=1e-6)):
        raise ValueError("q is not a valid probability distribution")

    if torch.any((p > 0) & (q == 0)):
        return float('inf')

    mask = p > 0
    kl = torch.sum(p[mask] * torch.log(p[mask] / q[mask]))
    return float(kl.item())

